def check_balanced_brackets(self):
    """
    Checks if the expression has balanced brackets.
    :return: True if the expression has balanced brackets, False otherwise.
    >>> b = BalancedBrackets("a(b)c")
    >>> b.check_balanced_brackets()
    True

    """
    stack = []
    bracket_pairs = {'(': ')', '[': ']', '{': '}'}
    opening_brackets = set(bracket_pairs.keys())
    closing_brackets = set(bracket_pairs.values())

    for char in self.expression:
        if char in opening_brackets:
            stack.append(char)
        elif char in closing_brackets:
            if not stack:
                return False
            last_opening = stack.pop()
            if bracket_pairs[last_opening] != char:
                return False

    return len(stack) == 0

def calculate_binary_info(self):
    """
    Calculate the binary string information, including the percentage of 0 and 1, and the total length of the binary string.
    >>> bdp = BinaryDataProcessor("0110100001100101011011000110110001101111")
    >>> bdp.calculate_binary_info()
    {'Zeroes': 0.475, 'Ones': 0.525, 'Bit length': 40}

    """
    binary_string = self.binary_string
    total_length = len(binary_string)

    if total_length == 0:
        return {'Zeroes': 0.0, 'Ones': 0.0, 'Bit length': 0}

    count_zeros = binary_string.count('0')
    count_ones = binary_string.count('1')

    percentage_zeros = count_zeros / total_length
    percentage_ones = count_ones / total_length

    return {
        'Zeroes': percentage_zeros,
        'Ones': percentage_ones,
        'Bit length': total_length
    }

def remove_book(self, title, quantity):
    """
    Remove one or several books from inventory which is sorted by book title.
    Raise false while get invalid input.
    :param title: str, the book title
    :param quantity: int
    """
    if not isinstance(title, str) or not isinstance(quantity, int):
        raise ValueError("Invalid input")

    if quantity <= 0:
        raise ValueError("Invalid input")

    if not hasattr(self, 'inventory'):
        self.inventory = {}

    if title not in self.inventory:
        raise ValueError("Invalid input")

    if self.inventory[title] < quantity:
        raise ValueError("Invalid input")

    self.inventory[title] -= quantity

    if self.inventory[title] == 0:
        del self.inventory[title]

