def find_blank(self, state):
    """
    Find the blank position of current state, which is the 0 element.
    :param state: a 3*3 size list of Integer, stores the current state.
    :return i, j: two Integers, represent the coordinate of the blank block.
    >>> eightPuzzle = EightPuzzle([[2, 3, 4], [5, 8, 1], [6, 0, 7]])
    >>> eightPuzzle.find_blank([[2, 3, 4], [5, 8, 1], [6, 0, 7]])
    (2, 1)
    """
    for i in range(len(state)):
        for j in range(len(state[i])):
            if state[i][j] == 0:
                return (i, j)

def move(self, state, direction):
    """
    Find the blank block, then makes the board moves forward the given direction.
    :param state: a 3*3 size list of Integer, stores the state before moving.
    :param direction: str, only has 4 direction 'up', 'down', 'left', 'right'
    :return new_state: a 3*3 size list of Integer, stores the state after moving.
    >>> eightPuzzle.move([[2, 3, 4], [5, 8, 1], [6, 0, 7]], 'left')
    [[2, 3, 4], [5, 8, 1], [0, 6, 7]]
    """
    # Create a deep copy of the state to avoid modifying the original
    new_state = [row[:] for row in state]

    # Find the position of the blank (0)
    blank_row, blank_col = None, None
    for i in range(3):
        for j in range(3):
            if state[i][j] == 0:
                blank_row, blank_col = i, j
                break
        if blank_row is not None:
            break

    # Determine the new position based on direction
    # Note: moving the blank "left" means swapping with the tile to its left
    if direction == 'left':
        if blank_col > 0:
            new_state[blank_row][blank_col] = new_state[blank_row][blank_col - 1]
            new_state[blank_row][blank_col - 1] = 0
    elif direction == 'right':
        if blank_col < 2:
            new_state[blank_row][blank_col] = new_state[blank_row][blank_col + 1]
            new_state[blank_row][blank_col + 1] = 0
    elif direction == 'up':
        if blank_row > 0:
            new_state[blank_row][blank_col] = new_state[blank_row - 1][blank_col]
            new_state[blank_row - 1][blank_col] = 0
    elif direction == 'down':
        if blank_row < 2:
            new_state[blank_row][blank_col] = new_state[blank_row + 1][blank_col]
            new_state[blank_row + 1][blank_col] = 0

    return new_state

def process_excel_data(self, N, save_file_name):
    """
    Change the specified column in the Excel file to uppercase
    :param N: int, The serial number of the column that want to change
    :param save_file_name: str, source file name
    :return:(int, str), The former is the return value of write_excel, while the latter is the saved file name of the processed data
    >>> processor = ExcelProcessor()
    >>> success, output_file = processor.process_excel_data(1, 'test_data.xlsx')
    """
    import openpyxl

    # Read the Excel file
    try:
        workbook = openpyxl.load_workbook(save_file_name)
        sheet = workbook.active

        # Process the specified column (N is 1-indexed)
        for row in sheet.iter_rows(min_row=1, min_col=N, max_col=N):
            for cell in row:
                if cell.value is not None:
                    # Convert cell value to uppercase if it's a string
                    if isinstance(cell.value, str):
                        cell.value = cell.value.upper()

        # Save the modified workbook
        output_file_name = f"processed_{save_file_name}"
        workbook.save(output_file_name)
        workbook.close()

        # Assuming write_excel returns 1 for success
        return (1, output_file_name)

    except Exception as e:
        # Return 0 for failure
        return (0, save_file_name)

@staticmethod
def is_operator(c):
    """
    Check if a character is an operator in {'+', '-', '*', '/', '(', ')', '%'}
    :param c: string, the character to be checked
    :return: bool, True if the character is an operator, False otherwise
    >>> expression_calculator = ExpressionCalculator()
    >>> expression_calculator.is_operator("+")
    True

    """
    return c in {'+', '-', '*', '/', '(', ')', '%'}

@staticmethod
def _calculate(first_value, second_value, current_op):
    """
    Perform the mathematical calculation based on the given operands and operator
    :param first_value: string, the first operand
    :param second_value: string, the second operand
    :param current_op: string, the operator
    :return: decimal.Decimal, the calculated result
    >>> expression_calculator = ExpressionCalculator()
    >>> expression_calculator._calculate("2", "3", "+")
    5.0

    """
    from decimal import Decimal

    first = Decimal(first_value)
    second = Decimal(second_value)

    if current_op == '+':
        return first + second
    elif current_op == '-':
        return first - second
    elif current_op == '*':
        return first * second
    elif current_op == '/':
        return first / second
    elif current_op == '//':
        return first // second
    elif current_op == '%':
        return first % second
    elif current_op == '**':
        return first ** second
    else:
        raise ValueError(f"Unsupported operator: {current_op}")

