def is_valid(self):
    """
    Judge whether the IP address is valid, that is, whether the IP address is composed of four Decimal digits separated by '.'. Each digit is greater than or equal to 0 and less than or equal to 255
    :return: bool
    >>> ipaddress = IPAddress("10.10.10.10")
    >>> ipaddress.is_valid()
    True
    """
    try:
        parts = self.ip_address.split('.')

        if len(parts) != 4:
            return False

        for part in parts:
            # Check if part is empty or not a valid number
            if not part or (part[0] == '0' and len(part) > 1):
                return False

            # Check if all characters are digits
            if not part.isdigit():
                return False

            # Convert to integer and check range
            num = int(part)
            if num < 0 or num > 255:
                return False

        return True
    except:
        return False

def update(self, predicted_labels, true_labels):
    """
    Update the number of all four samples(true_positives, false_positives, false_negatives, true_negatives)
    :param predicted_labels: list, predicted results
    :param true_labels: list, true labels
    :return: None, change the number of corresponding samples
    >>> mc = MetricsCalculator()
    >>> mc.update([1, 1, 0, 0], [1, 0, 0, 1])
    (self.true_positives, self.false_positives, self.false_negatives, self.true_negatives) = (1, 1, 1, 1)
    """
    for predicted, true in zip(predicted_labels, true_labels):
        if predicted == 1 and true == 1:
            self.true_positives += 1
        elif predicted == 1 and true == 0:
            self.false_positives += 1
        elif predicted == 0 and true == 1:
            self.false_negatives += 1
        elif predicted == 0 and true == 0:
            self.true_negatives += 1

def generate_mine_sweeper_map(self):
    """
    Generates a minesweeper map with the given size of the board and the number of mines,the given parameter n is the size of the board,the size of the board is n*n,the parameter k is the number of mines,'X' represents the mine,other numbers represent the number of mines around the position.
    :return: The minesweeper map, list.
    >>> minesweeper_game = MinesweeperGame(3, 1)
    >>> minesweeper_game.generate_mine_sweeper_map()
    [['X', 1, 0], [1, 1, 0], [0, 0, 0]]

    """
    import random

    # Initialize the board with zeros
    board = [[0 for _ in range(self.n)] for _ in range(self.n)]

    # Randomly place k mines on the board
    positions = [(i, j) for i in range(self.n) for j in range(self.n)]
    mine_positions = random.sample(positions, self.k)

    # Place mines on the board
    for row, col in mine_positions:
        board[row][col] = 'X'

    # Calculate numbers for non-mine cells
    for i in range(self.n):
        for j in range(self.n):
            if board[i][j] != 'X':
                # Count adjacent mines
                count = 0
                for di in [-1, 0, 1]:
                    for dj in [-1, 0, 1]:
                        if di == 0 and dj == 0:
                            continue
                        ni, nj = i + di, j + dj
                        if 0 <= ni < self.n and 0 <= nj < self.n:
                            if board[ni][nj] == 'X':
                                count += 1
                board[i][j] = count

    return board

def sweep(self, x, y):
    """
    Sweeps the given position.
    :param x: The x coordinate of the position, int.
    :param y: The y coordinate of the position, int.
    :return: True if the player has won the game, False otherwise,if the game still continues, return the player map, list.
    >>> minesweeper_game = MinesweeperGame(3, 1)
    >>> minesweeper_game.minesweeper_map = [['X', 1, 0], [1, 1, 0], [0, 0, 0]]
    >>> minesweeper_game.player_map = [['-', '-', '-'], ['-', '-', '-'], ['-', '-', '-']]
    >>> minesweeper_game.sweep(1, 1)
    [['-', '-', '-'], ['-', 1, '-'], ['-', '-', '-']]

    """
    # Check if the position contains a mine
    if self.minesweeper_map[x][y] == 'X':
        return False

    # Reveal the cell
    self.player_map[x][y] = self.minesweeper_map[x][y]

    # If the cell is 0, recursively reveal adjacent cells
    if self.minesweeper_map[x][y] == 0:
        for dx in [-1, 0, 1]:
            for dy in [-1, 0, 1]:
                if dx == 0 and dy == 0:
                    continue
                nx, ny = x + dx, y + dy
                # Check bounds
                if 0 <= nx < len(self.minesweeper_map) and 0 <= ny < len(self.minesweeper_map[0]):
                    # Only sweep if not already revealed
                    if self.player_map[nx][ny] == '-':
                        self.sweep(nx, ny)

    # Check if the player has won (all non-mine cells revealed)
    for i in range(len(self.minesweeper_map)):
        for j in range(len(self.minesweeper_map[0])):
            if self.minesweeper_map[i][j] != 'X' and self.player_map[i][j] == '-':
                return self.player_map

    return True

