def format(self, x):
    """
    Converts a number into words format
    :param x: int or float, the number to be converted into words format
    :return: str, the number in words format
    >>> formatter = NumberWordFormatter()
    >>> formatter.format(123456)
    "ONE HUNDRED AND TWENTY THREE THOUSAND FOUR HUNDRED AND FIFTY SIX ONLY"
    """
    if x == 0:
        return "ZERO ONLY"

    # Handle negative numbers
    if x < 0:
        return "MINUS " + self.format(-x)

    # Separate integer and decimal parts
    if isinstance(x, float):
        integer_part = int(x)
        decimal_part = round((x - integer_part) * 100)
        if decimal_part > 0:
            result = self.format(integer_part).replace(" ONLY", "")
            result += " AND " + self.format(decimal_part).replace(" ONLY", "") + " CENTS ONLY"
            return result
        else:
            x = integer_part

    # Define word mappings
    ones = ["", "ONE", "TWO", "THREE", "FOUR", "FIVE", "SIX", "SEVEN", "EIGHT", "NINE"]
    teens = ["TEN", "ELEVEN", "TWELVE", "THIRTEEN", "FOURTEEN", "FIFTEEN", 
             "SIXTEEN", "SEVENTEEN", "EIGHTEEN", "NINETEEN"]
    tens = ["", "", "TWENTY", "THIRTY", "FORTY", "FIFTY", "SIXTY", "SEVENTY", "EIGHTY", "NINETY"]

    def convert_below_thousand(n):
        if n == 0:
            return ""
        elif n < 10:
            return ones[n]
        elif n < 20:
            return teens[n - 10]
        elif n < 100:
            result = tens[n // 10]
            if n % 10 != 0:
                result += " " + ones[n % 10]
            return result
        else:
            result = ones[n // 100] + " HUNDRED"
            remainder = n % 100
            if remainder != 0:
                result += " AND " + convert_below_thousand(remainder)
            return result

    # Handle numbers by groups of thousands
    if x < 1000:
        return convert_below_thousand(x) + " ONLY"
    elif x < 1000000:
        thousands = x // 1000
        remainder = x % 1000
        result = convert_below_thousand(thousands) + " THOUSAND"
        if remainder != 0:
            result += " " + convert_below_thousand(remainder)
        return result + " ONLY"
    elif x < 1000000000:
        millions = x // 1000000
        remainder = x % 1000000
        result = convert_below_thousand(millions) + " MILLION"
        if remainder >= 1000:
            thousands = remainder // 1000
            result += " " + convert_below_thousand(thousands) + " THOUSAND"
            remainder = remainder % 1000
        if remainder != 0:
            result += " " + convert_below_thousand(remainder)
        return result + " ONLY"
    else:
        billions = x // 1000000000
        remainder = x % 1000000000
        result = convert_below_thousand(billions) + " BILLION"
        if remainder >= 1000000:
            millions = remainder // 1000000
            result += " " + convert_below_thousand(millions) + " MILLION"
            remainder = remainder % 1000000
        if remainder >= 1000:
            thousands = remainder // 1000
            result += " " + convert_below_thousand(thousands) + " THOUSAND"
            remainder = remainder % 1000
        if remainder != 0:
            result += " " + convert_below_thousand(remainder)
        return result + " ONLY"

def send(self, info):
    """
    Send information containing address and content
    :param info: dict, information dictionary containing address and content
    :return: if successfully sent, return nothing; otherwise, return a string indicating an error message
    >>> server.send({"addr":66,"content":"ABC"})
    self.send_struct = {"addr":66,"content":"ABC"}
    """
    try:
        if not isinstance(info, dict):
            return "Error: info must be a dictionary"

        if "addr" not in info or "content" not in info:
            return "Error: info must contain 'addr' and 'content' keys"

        self.send_struct = info

    except Exception as e:
        return f"Error: {str(e)}"

def show(self, type):
    """
    Returns struct of the specified type
    :param type: string, the type of struct to be returned, which can be 'send' or 'receive'
    :return: if type is equal to 'send' or 'receive', return the corresponding struct; otherwise, return False
    >>> server.recv({"addr":88,"content":"abc"})
    >>> server.send({"addr":66,"content":"ABC"})
    >>> server.show("send")
    {"addr":66,"content":"ABC"}
    """
    if type == 'send':
        return self.send_struct
    elif type == 'receive':
        return self.receive_struct
    else:
        return False

def is_board_full(self):
    """
    Check if the game board is completely filled.
    :return: bool, indicating whether the game board is full or not
    >>> ttt.is_board_full()
    False
    """
    for row in self.board:
        for cell in row:
            if cell is None or cell == '' or cell == ' ':
                return False
    return True

import math

@staticmethod
def compute_idf_weight_dict(total_num, number_dict):
    """
    Calculate log(total_num+1/count+1) for each count in number_dict
    :param total_num: int
    :param number_dict: dict
    :return: dict
    >>> num_dict = {'key1':0.1, 'key2':0.5}
    >>> VectorUtil.compute_idf_weight_dict(2, num_dict)
    {'key1': 1.0033021088637848, 'key2': 0.6931471805599453}
    """
    result = {}
    for key, count in number_dict.items():
        result[key] = math.log((total_num + 1) / (count + 1))
    return result

def add_product(self, product_id, name, quantity):
    """
    Add product to inventory and plus the quantity if it has existed in inventory.
    Or just add new product to dict otherwise.
    :param product_id: int
    :param name: str, product name
    :param quantity: int, product quantity
    >>> warehouse.add_product(1, "product1", 3)
    >>> warehouse.inventory
    {1: {'name': 'product1', 'quantity': 3}}
    """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity
    else:
        self.inventory[product_id] = {'name': name, 'quantity': quantity}

def update_product_quantity(self, product_id, quantity):
    """
    According to product_id, add the quantity to the corresponding product in inventory.
    >>> warehouse.add_product(1, "product1", 3)
    >>> warehouse.update_product_quantity(1, -1)
    >>> warehouse.inventory
    {1: {'name': 'product1', 'quantity': 2}}
    """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity

def text2int(self, textnum):
    """
    Convert the word string to the corresponding integer string
    :param textnum: string, the word string to be converted
    :return: string, the final converted integer string
    >>> w2n = Words2Numbers()
    >>> w2n.text2int("thirty-two")
    "32"
    """
    ones = {
        "zero": 0, "one": 1, "two": 2, "three": 3, "four": 4, "five": 5,
        "six": 6, "seven": 7, "eight": 8, "nine": 9, "ten": 10,
        "eleven": 11, "twelve": 12, "thirteen": 13, "fourteen": 14,
        "fifteen": 15, "sixteen": 16, "seventeen": 17, "eighteen": 18,
        "nineteen": 19
    }

    tens = {
        "twenty": 20, "thirty": 30, "forty": 40, "fifty": 50,
        "sixty": 60, "seventy": 70, "eighty": 80, "ninety": 90
    }

    scales = {
        "hundred": 100,
        "thousand": 1000,
        "million": 1000000,
        "billion": 1000000000,
        "trillion": 1000000000000
    }

    textnum = textnum.lower().replace(" and ", " ").replace("-", " ")
    words = textnum.split()

    result = 0
    current = 0

    for word in words:
        if word in ones:
            current += ones[word]
        elif word in tens:
            current += tens[word]
        elif word in scales:
            if word == "hundred":
                current *= scales[word]
            else:
                current *= scales[word]
                result += current
                current = 0

    result += current
    return str(result)
